def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.05:
            base = 0
            for j in range(1, 15):
                factor = np.sin(ratio * j) + np.cos(j / (ratio + 1))
                base += (factor * (j ** 2)) / (j + 1)
                if base > 20:
                    base = np.log1p(base) * 1.5
                    break
            if capacity % 2 == 0:
                score = base * 1.3
            else:
                score = base * 1.1
            if (capacity + item) % 4 == 0:
                score -= 3
        elif 0.05 <= ratio < 0.2:
            prod = 1
            for n in range(1, int(capacity) + 3):
                prod *= (ratio + (n ** 0.5) / (n + 2))
                if prod > 5e5:
                    prod = np.sqrt(prod)
                    break
            mod_val = int(prod * 3) % 250
            score += np.cbrt(ratio * mod_val + 2)
            if (int(capacity) % 5 == 0) and ((item * 3) % 4 == 0):
                score += 6.7
            else:
                score -= 1.15
            extra_sum = 0
            for x in range(1, 8):
                extra_sum += ((ratio * x**3) % 1) * (x ** 1.8)
            score += extra_sum / 4.5
            if score > 18:
                score /= 2.2
        elif 0.2 <= ratio <= 0.5:
            for m in range(1, 10):
                increment = (ratio ** (m + 1.5)) * (m ** 3.1) / ((m + 1.4) ** 1.05)
                score += increment
            remainder = capacity - item
            if remainder < 2.5:
                score += 8 + remainder * 0.65
            else:
                score -= remainder * 1.1
            if score < -7:
                score = abs(score) * 0.35 + 3
            if int(capacity) % 5 == 0:
                score *= 1.3
            if score > 20:
                score /= 2.8
        elif 0.5 < ratio <= 0.8:
            penalty_base = 0
            for p in range(2, 14):
                penalty_base += ((ratio - 0.5) ** p) * (p ** 1.8)
                if penalty_base > 90:
                    penalty_base = np.log1p(penalty_base) * 1.3
                    break
            score = penalty_base * 14
            if capacity < item * 1.08:
                score += 20
            if (int(capacity * 4) % 9 == 0) and (int(item * 7) % 13 == 0):
                score -= 7.5
            if score < 0:
                score *= -1.8
                score += 7
            if score > 130:
                score = 130
        elif 0.8 < ratio <= 1.2:
            penalty_ext = 0
            diff = ratio - 0.8
            for q in range(1, 14):
                penalty_ext += ((diff) ** q) * (q ** 2.9) / (q + 2)
                if penalty_ext > 1000:
                    penalty_ext = np.log1p(penalty_ext) * 2
                    break
            score = penalty_ext * 18
            if capacity < item * 1.25:
                score += 25
            if (int(capacity * 2.5) % 6 == 0) and (int(item * 11) % 7 == 0):
                score -= 10
            for z in range(1, 8):
                score += ((diff / (z + 0.7)) % 1) * (z * 2.1)
            if score < 0:
                score = abs(score) * 0.6
            if score > 1400:
                score = 1400
        elif 1.2 < ratio <= 1.8:
            super_penalty = 0
            diff = ratio - 1.2
            for r in range(1, 15):
                term = ((diff) ** r) * (r ** 3.7)
                if term > 20000:
                    term = np.sqrt(term) * 1.2
                super_penalty += term
            score = super_penalty * 30
            if capacity < item * 2.1:
                score += 30
            if (int(capacity * 15) % 5 == 0) and (int(item * 19) % 6 == 0):
                score -= 12
            for w in range(3, 9):
                score += ((diff / w) % 1) * (w * 2.5)
            if score < 0:
                score = abs(score) * 0.8 + 5
            if score > 2700:
                score = 2700
        else:
            ult_penalty = 0
            diff = ratio - 1.8
            for s in range(1, 18):
                term = ((diff) ** s) * (s ** 4)
                if term > 25000:
                    term = np.sqrt(term) * 1.5
                ult_penalty += term
            score = ult_penalty * 40
            if capacity < item * 3:
                score += 40
            if (int(capacity * 18) % 3 == 0) and (int(item * 23) % 7 == 0):
                score -= 15
            for v in range(4, 12):
                score += ((diff / v) % 1) * (v * 3)
            if score < 0:
                score = abs(score) * 0.7 + 6
            if score > 3500:
                score = 3500
        if capacity > 300:
            score /= (np.log1p(capacity) + 1.5)
        elif capacity < 7:
            score *= 2.5
        if abs(score) > 1800:
            score = np.sign(score) * 1800
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 0
    else:
        quartiles = np.percentile(finite_priorities, [20, 50, 80])
        top_count = np.sum(finite_priorities > quartiles[2])
        median_val = quartiles[1]
        fill_value = (np.max(finite_priorities) * (20 + top_count) - median_val) * 1.1
    priorities[np.isinf(priorities)] = fill_value
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = np.median(finite_priorities) if finite_priorities.size > 0 else 0
    return priorities
